SELECT measure_name
FROM measures
WHERE updated_at = (SELECT MAX(updated_at) FROM measures);

SELECT time_period
FROM time_periods
ORDER BY start_date ASC;

SELECT measure_name, updated_at
FROM measures
ORDER BY updated_at DESC;

SELECT measure_name
FROM measures
ORDER BY measure_name;

SELECT measure_name, unit
FROM measures
WHERE measure_id > 10;
